import{_ as e,o,c as l,ae as t}from"./chunks/framework.C7FLYIpo.js";const k=JSON.parse('{"title":"음성 Wake (macOS)","description":"mac 앱의 음성 wake 및 push-to-talk 모드와 라우팅 세부 사항","frontmatter":{"title":"음성 Wake (macOS)","description":"mac 앱의 음성 wake 및 push-to-talk 모드와 라우팅 세부 사항"},"headers":[],"relativePath":"platforms/mac/voicewake.md","filePath":"platforms/mac/voicewake.md","lastUpdated":null}'),i={name:"platforms/mac/voicewake.md"};function r(s,a,c,n,d,h){return o(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="음성-wake-및-push-to-talk" tabindex="-1">음성 Wake 및 Push-to-Talk <a class="header-anchor" href="#음성-wake-및-push-to-talk" aria-label="Permalink to &quot;음성 Wake 및 Push-to-Talk&quot;">​</a></h1><h2 id="모드" tabindex="-1">모드 <a class="header-anchor" href="#모드" aria-label="Permalink to &quot;모드&quot;">​</a></h2><ul><li><strong>Wake 단어 모드</strong> (기본값): 항상 켜져 있는 음성 인식기가 트리거 토큰 (<code>swabbleTriggerWords</code>)을 기다립니다. 일치하면 캡처를 시작하고 부분 텍스트와 함께 오버레이를 표시하며 침묵 후 자동으로 전송합니다.</li><li><strong>Push-to-talk (오른쪽 Option 키 누르기)</strong>: 오른쪽 Option 키를 눌러 즉시 캡처합니다. 트리거가 필요하지 않습니다. 오버레이는 눌린 상태에서 표시됩니다. 해제하면 짧은 지연 후 최종화되고 전달되므로 텍스트를 조정할 수 있습니다.</li></ul><h2 id="런타임-동작-wake-단어" tabindex="-1">런타임 동작 (wake 단어) <a class="header-anchor" href="#런타임-동작-wake-단어" aria-label="Permalink to &quot;런타임 동작 (wake 단어)&quot;">​</a></h2><ul><li>음성 인식기는 <code>VoiceWakeRuntime</code>에 있습니다.</li><li>트리거는 wake 단어와 다음 단어 사이에 <strong>의미 있는 휴지</strong> (~0.55초 간격)가 있을 때만 발동합니다. 명령이 시작되기 전에도 휴지에서 오버레이/차임이 시작될 수 있습니다.</li><li>침묵 창: 음성이 흐를 때 2.0초, 트리거만 들린 경우 5.0초.</li><li>하드 스톱: 폭주 세션을 방지하기 위해 120초.</li><li>세션 간 디바운스: 350ms.</li><li>오버레이는 커밋된/휘발성 색상으로 <code>VoiceWakeOverlayController</code>를 통해 구동됩니다.</li><li>전송 후 인식기가 다음 트리거를 수신하기 위해 깨끗하게 재시작됩니다.</li></ul><h2 id="라이프사이클-불변성" tabindex="-1">라이프사이클 불변성 <a class="header-anchor" href="#라이프사이클-불변성" aria-label="Permalink to &quot;라이프사이클 불변성&quot;">​</a></h2><ul><li>음성 Wake가 활성화되어 있고 권한이 부여된 경우 wake 단어 인식기가 수신 대기 중이어야 합니다 (명시적 push-to-talk 캡처 중 제외).</li><li>X 버튼을 통한 수동 닫기를 포함한 오버레이 가시성은 인식기 재개를 방해하지 않아야 합니다.</li></ul><h2 id="고착된-오버레이-실패-모드-이전" tabindex="-1">고착된 오버레이 실패 모드 (이전) <a class="header-anchor" href="#고착된-오버레이-실패-모드-이전" aria-label="Permalink to &quot;고착된 오버레이 실패 모드 (이전)&quot;">​</a></h2><p>이전에는 오버레이가 표시된 상태로 고착되어 수동으로 닫으면 런타임의 재시작 시도가 오버레이 가시성으로 인해 차단될 수 있었고 이후 재시작이 예약되지 않아 Voice Wake가 &quot;죽은&quot; 것처럼 보일 수 있었습니다.</p><p>강화:</p><ul><li>Wake 런타임 재시작이 더 이상 오버레이 가시성으로 차단되지 않습니다.</li><li>오버레이 닫기 완료가 <code>VoiceSessionCoordinator</code>를 통해 <code>VoiceWakeRuntime.refresh(...)</code>를 트리거하므로 수동 X 닫기가 항상 수신 대기를 재개합니다.</li></ul><h2 id="push-to-talk-세부-사항" tabindex="-1">Push-to-talk 세부 사항 <a class="header-anchor" href="#push-to-talk-세부-사항" aria-label="Permalink to &quot;Push-to-talk 세부 사항&quot;">​</a></h2><ul><li>핫키 감지는 <strong>오른쪽 Option</strong> (<code>keyCode 61</code> + <code>.option</code>)에 대한 글로벌 <code>.flagsChanged</code> 모니터를 사용합니다. 이벤트만 관찰합니다 (삼키지 않음).</li><li>캡처 파이프라인은 <code>VoicePushToTalk</code>에 있습니다: 즉시 음성을 시작하고, 부분을 오버레이로 스트리밍하며, 해제 시 <code>VoiceWakeForwarder</code>를 호출합니다.</li><li>Push-to-talk이 시작되면 두 개의 오디오 탭이 경쟁하지 않도록 wake 단어 런타임을 일시 중지합니다. 해제 후 자동으로 재시작됩니다.</li><li>권한: 마이크 + 음성이 필요합니다. 이벤트를 보려면 접근성/입력 모니터링 승인이 필요합니다.</li><li>외부 키보드: 일부는 오른쪽 Option을 예상대로 노출하지 않을 수 있습니다. 사용자가 누락을 보고하면 대체 단축키를 제공하십시오.</li></ul><h2 id="사용자-대면-설정" tabindex="-1">사용자 대면 설정 <a class="header-anchor" href="#사용자-대면-설정" aria-label="Permalink to &quot;사용자 대면 설정&quot;">​</a></h2><ul><li><strong>Voice Wake</strong> 토글: wake 단어 런타임을 활성화합니다.</li><li><strong>Cmd+Fn을 눌러 말하기</strong>: push-to-talk 모니터를 활성화합니다. macOS &lt; 26에서는 비활성화됩니다.</li><li>언어 및 마이크 선택기, 실시간 레벨 미터, 트리거 단어 테이블, 테스터 (로컬 전용; 전달하지 않음).</li><li>마이크 선택기는 기기가 연결 해제되면 마지막 선택을 유지하고 연결 해제 힌트를 표시하며 돌아올 때까지 시스템 기본값으로 일시적으로 대체됩니다.</li><li><strong>소리</strong>: 트리거 감지 및 전송 시 차임. 기본값은 macOS &quot;Glass&quot; 시스템 소리. 각 이벤트에 대해 <code>NSSound</code>로 로드 가능한 파일 (예: MP3/WAV/AIFF)을 선택하거나 <strong>소리 없음</strong>을 선택할 수 있습니다.</li></ul><h2 id="전달-동작" tabindex="-1">전달 동작 <a class="header-anchor" href="#전달-동작" aria-label="Permalink to &quot;전달 동작&quot;">​</a></h2><ul><li>음성 Wake가 활성화되면 전사가 활성 게이트웨이/에이전트 (앱의 나머지가 사용하는 동일한 로컬 vs 원격 모드)로 전달됩니다.</li><li>응답은 <strong>마지막으로 사용된 메인 공급자</strong> (WhatsApp/Telegram/Discord/WebChat)로 전달됩니다. 전달이 실패하면 오류가 로깅되고 실행은 WebChat/세션 로그를 통해 여전히 표시됩니다.</li></ul><h2 id="전달-페이로드" tabindex="-1">전달 페이로드 <a class="header-anchor" href="#전달-페이로드" aria-label="Permalink to &quot;전달 페이로드&quot;">​</a></h2><ul><li><code>VoiceWakeForwarder.prefixedTranscript(_:)</code>는 전송 전에 머신 힌트를 앞에 추가합니다. wake 단어와 push-to-talk 경로 간에 공유됩니다.</li></ul><h2 id="빠른-확인" tabindex="-1">빠른 확인 <a class="header-anchor" href="#빠른-확인" aria-label="Permalink to &quot;빠른 확인&quot;">​</a></h2><ul><li>Push-to-talk을 켜고 Cmd+Fn을 누르고, 말하고, 해제합니다: 오버레이가 부분을 표시한 다음 전송해야 합니다.</li><li>누르는 동안 메뉴 바 귀가 확대 상태를 유지해야 합니다 (<code>triggerVoiceEars(ttl:nil)</code> 사용). 해제 후 축소됩니다.</li></ul>',21)])])}const p=e(i,[["render",r]]);export{k as __pageData,p as default};
